import urllib.request, urllib.error, sys
base='http://localhost:5000'
paths=['/','/page','/flag','/flag.txt','/FLAG','/flag/','/secret','/secrets','/api/flag','/api/secret','/internal/flag','/hidden/flag','/private','/private/flag','/admin','/admin/flag','/debug','/__debugger__','/__debug__/', '/console','/robots.txt','/sitemap.xml','/.well-known/security.txt']
results=[]
for p in paths:
    url=base+p if not base.endswith('/') else base[:-1]+p
    try:
        with urllib.request.urlopen(url, timeout=5) as r:
            body=r.read(200)
            results.append((p, r.status, len(body), body.decode('utf-8','ignore')))
    except urllib.error.HTTPError as e:
        body=e.read(200)
        results.append((p, e.code, len(body), body.decode('utf-8','ignore')))
    except Exception as e:
        results.append((p, 'ERR', 0, str(e)))
for p,code,blen,preview in results:
    print(f'{p} -> {code}, {blen} bytes')
    if code==200 and blen>0:
        print(preview.replace('\n',' ')[:120])

